const source = $input.item.json.output;

// Escape unescaped LaTeX special characters in AI-generated text.
// Process line-by-line: preserve pure comment lines (starting with %),
// fix bare % on all other lines so they don't terminate \resumeItem{} args.
const fixed = source.split('\n').map(line => {
  if (line.trimStart().startsWith('%')) return line;
  // Replace % not already preceded by a backslash
  return line.replace(/(?<!\\)%/g, '\\%');
}).join('\n');

return [{ json: { latex: fixed } }];

// Build a shareable Drive link from the uploaded file ID
